#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Cap async-enrich concurrency to a safe-but-fast level (prevents re-saturating the 200
conn ceiling that 2048 lanes would blow), restart, and measure the real done/min rate."""
import os,sys,json,time,subprocess
def sh(c,t=30):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=30):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return r.stdout.strip() if r.returncode==0 else "ERR"
out={"kind":"async_tune","ts":int(time.time())}
try:
    for base in ["atlas-enrich-async","atlas-enrich-async-batch"]:
        dd="/etc/systemd/system/%s@.service.d"%base
        os.makedirs(dd,exist_ok=True)
        open(dd+"/override.conf","w").write("[Service]\nEnvironment=ATLAS_ASYNC_LANES=400\nEnvironment=ATLAS_ASYNC_PG_POOL=8\nEnvironment=ATLAS_ASYNC_DB_WRITERS=6\n")
    dd="/etc/systemd/system/atlas-enrich-async-ramp.service.d"; os.makedirs(dd,exist_ok=True)
    open(dd+"/override.conf","w").write("[Service]\nEnvironment=ATLAS_ASYNC_LANES=400\nEnvironment=ATLAS_ASYNC_PG_POOL=8\n")
    out["reload"]=sh("systemctl daemon-reload 2>&1; echo rc=$?")
    out["restart"]=sh("systemctl reset-failed 'atlas-enrich-async*' 2>/dev/null; systemctl restart atlas-enrich-async@1.service atlas-enrich-async-batch@1.service 2>&1; echo rc=$?")
    time.sleep(20)  # warmup
    d0=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue")
    time.sleep(40)
    d1=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue")
    out["done_t0"]=d0; out["done_t1"]=d1
    try: out["done_per_min"]=round((int(d1)-int(d0))*60.0/40,1)
    except Exception: pass
    out["state"]=sh("for u in atlas-enrich-async@1 atlas-enrich-async-batch@1; do echo $u=$(systemctl is-active $u.service); done")
    out["pg_conns"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    out["async_doing"]=psql("SELECT coalesce(state,'?')||':'||count(*) FROM pg_stat_activity WHERE application_name ILIKE '%async%' OR query ILIKE '%business%' GROUP BY state")
    out["journal"]=sh("journalctl -u atlas-enrich-async@1.service -n 12 --no-pager 2>&1 | tail -12")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/async-tune.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"async_tune","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(5):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
